// src/bin/krnlts-watch.ts
import fs from "fs";
import path from "path";
function scanDirectory(dir, results = []) {
  if (!fs.existsSync(dir)) return results;
  const list = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of list) {
    if (entry.isDirectory()) {
      if (entry.name === "node_modules" || entry.name === "dist" || entry.name === ".git") continue;
      const fullPath = path.join(dir, entry.name);
      if (entry.name === "functionalities") {
        const funcs = fs.readdirSync(fullPath, { withFileTypes: true });
        for (const f of funcs) {
          if (f.isDirectory()) {
            results.push({
              funcPath: path.join(fullPath, f.name),
              funcName: f.name
            });
          }
        }
      } else {
        scanDirectory(fullPath, results);
      }
    }
  }
  return results;
}
function parseExports(filePath, defaultName) {
  const content = fs.readFileSync(filePath, "utf8");
  const named = [];
  let hasDefault = false;
  const namedRegex = /export\s+(?:const|let|var|function|class|async\s+function)\s+([a-zA-Z0-9_$]+)/g;
  let match;
  while ((match = namedRegex.exec(content)) !== null) {
    if (match[1]) named.push(match[1]);
  }
  if (content.includes("export default")) {
    hasDefault = true;
  }
  return { named, hasDefault };
}
function generateDeclarations() {
  const projectRoot = process.cwd();
  console.log(`[KrnlWatcher] Scanning project at: ${projectRoot}`);
  const functionalities = scanDirectory(projectRoot);
  let dtsContent = `// Automatically generated by KrnlTS Magnetic Watcher. Do not edit manually.

`;
  dtsContent += `import { krnlSystemEntityBase, krnlEntityBase } from '@dinilmusick/krnlts';

`;
  const globalDeclarations = [];
  for (const func of functionalities) {
    const relativeFuncPath = path.relative(projectRoot, func.funcPath);
    const helpersDir = path.join(func.funcPath, "helper_functions");
    if (fs.existsSync(helpersDir)) {
      const files = fs.readdirSync(helpersDir);
      for (const file of files) {
        if (file.endsWith(".js") || file.endsWith(".ts")) {
          const filePath = path.join(helpersDir, file);
          const baseName = path.basename(file, path.extname(file));
          const importPath = `./${path.relative(projectRoot, filePath).replace(/\\/g, "/")}`;
          const { named, hasDefault } = parseExports(filePath, baseName);
          if (hasDefault) {
            globalDeclarations.push(`  const ${baseName}: typeof import('${importPath}')['default'];`);
          }
          for (const name of named) {
            globalDeclarations.push(`  const ${name}: typeof import('${importPath}')['${name}'];`);
          }
        }
      }
    }
    const eventsDir = path.join(func.funcPath, "events");
    if (fs.existsSync(eventsDir)) {
      const files = fs.readdirSync(eventsDir);
      for (const file of files) {
        if (file.endsWith(".js") || file.endsWith(".ts")) {
          const filePath = path.join(eventsDir, file);
          const baseName = path.basename(file, path.extname(file));
          const importPath = `./${path.relative(projectRoot, filePath).replace(/\\/g, "/")}`;
          const { named, hasDefault } = parseExports(filePath, baseName);
          if (hasDefault) {
            globalDeclarations.push(`  const ${baseName}: typeof import('${importPath}')['default'];`);
          }
          for (const name of named) {
            globalDeclarations.push(`  const ${name}: typeof import('${importPath}')['${name}'];`);
          }
        }
      }
    }
  }
  if (globalDeclarations.length > 0) {
    dtsContent += `declare global {
${Array.from(new Set(globalDeclarations)).join("\n")}
}
`;
  }
  const outPath = path.join(projectRoot, "krnl-magnetic.d.ts");
  fs.writeFileSync(outPath, dtsContent);
  console.log(`[KrnlWatcher] Generated type declarations file: ${outPath}`);
}
if (process.argv[1] && (process.argv[1].endsWith("krnlts-watch.ts") || process.argv[1].endsWith("krnlts-watch.js") || process.argv[1].endsWith("krnlts-watch"))) {
  generateDeclarations();
  if (process.argv.includes("--watch")) {
    console.log("[KrnlWatcher] Watch mode enabled. Monitoring directory changes...");
    fs.watch(process.cwd(), { recursive: true }, (eventType, filename) => {
      if (filename && (filename.endsWith(".js") || filename.endsWith(".ts")) && !filename.includes("krnl-magnetic.d.ts")) {
        try {
          generateDeclarations();
        } catch (e) {
        }
      }
    });
  }
}
export {
  generateDeclarations
};
